import React, { useEffect, useMemo, useState } from 'react';
import Particles from './Particles';

function Section({ id, title, children }) {
    return (
        <section id={id} className="section">
            <h2 className="sectionTitle">{title}</h2>
            <div className="sectionBody">{children}</div>
        </section>
    );
}

const App = () => {
    const [content, setContent] = useState(null);
    const [announcements, setAnnouncements] = useState([]);
    const [newAnnouncement, setNewAnnouncement] = useState({ name: '', description: '' });
    const [error, setError] = useState('');

    useEffect(() => {
        Promise.all([
            fetch('/content').then(r => r.json()),
            fetch('/items').then(r => r.json()),
        ])
            .then(([c, items]) => {
                setContent(c);
                setAnnouncements(Array.isArray(items) ? items : []);
            })
            .catch(() => setError('Backend not reachable. Start the PythonBackend on port 5000.'));
    }, []);

    const nav = useMemo(() => {
        const sectionLinks = (content?.sections || []).map(s => ({
            id: s.id,
            label: s.title,
        }));
        return [...sectionLinks, { id: 'announcements', label: 'Announcements' }, { id: 'contacts', label: 'Contacts' }];
    }, [content]);

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setNewAnnouncement(prev => ({ ...prev, [name]: value }));
    };

    const addAnnouncement = async () => {
        setError('');
        try {
            const resp = await fetch('/items', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(newAnnouncement),
            });
            const data = await resp.json();
            if (!resp.ok) {
                setError(data?.error || 'Failed to add announcement.');
                return;
            }
            setAnnouncements(prev => [...prev, { id: data.id, ...newAnnouncement }]);
            setNewAnnouncement({ name: '', description: '' });
        } catch {
            setError('Failed to add announcement. Backend not reachable.');
        }
    };

    return (
        <div className="app">
            <Particles
                particleCount={260}
                particleSpread={18}
                speed={0.2}
                particleColors={['#9aa7ff', '#7cf0ff', '#ffffff']}
                moveParticlesOnHover={true}
                particleHoverFactor={2}
                alphaParticles={true}
                particleBaseSize={42}
                sizeRandomness={0.65}
                cameraDistance={30}
                disableRotation={false}
                pixelRatio={window.devicePixelRatio}
                className="backgroundParticles"
            />

            <header className="header">
                <div className="container headerInner">
                    <div className="brand">
                        <div className="brandTitle">{content?.title || 'UG Academic Council (UGAC)'}</div>
                        <div className="brandSubtitle">
                            {content?.subtitle || 'Undergraduate Academic Council'}
                        </div>
                    </div>
                    <nav className="nav">
                        {nav.map(item => (
                            <a key={item.id} className="navLink" href={`#${item.id}`}>
                                {item.label}
                            </a>
                        ))}
                    </nav>
                </div>
            </header>

            <main className="container main">
                {error ? <div className="error">{error}</div> : null}

                <div className="hero">
                    <div className="heroCard">
                        <h1 className="heroTitle">Welcome</h1>
                        <p className="heroText">
                            This site hosts UGAC information, key processes, flowcharts, and announcements for students.
                        </p>
                        <div className="heroActions">
                            <a className="button" href="#announcements">
                                View announcements
                            </a>
                            <a className="button buttonSecondary" href="#contacts">
                                Contact UGAC
                            </a>
                        </div>
                    </div>
                </div>

                <Section id="overview" title="Overview">
                    <p>
                        {(content?.sections || []).find(s => s.id === 'overview')?.body || 'Loading overview...'}
                    </p>
                </Section>

                {(content?.sections || [])
                    .filter(s => s.id !== 'overview')
                    .map(section => {
                        if (section.id === 'flowcharts') {
                            const charts = section.flowcharts || [];
                            return (
                                <Section key={section.id} id={section.id} title={section.title}>
                                    {section.body ? <p>{section.body}</p> : null}
                                    {charts.length ? (
                                        <div className="grid">
                                            {charts.map((c, idx) => (
                                                <div key={`${c.title}-${idx}`} className="card">
                                                    <div className="cardTitle">{c.title}</div>
                                                    <div className="cardText">{c.description}</div>
                                                    {c.link ? (
                                                        <a className="cardLink" href={c.link} target="_blank" rel="noreferrer">
                                                            Open
                                                        </a>
                                                    ) : (
                                                        <div className="cardHint">Add a link in `PythonBackend/content.json`.</div>
                                                    )}
                                                </div>
                                            ))}
                                        </div>
                                    ) : (
                                        <p className="muted">No flowcharts added yet.</p>
                                    )}
                                </Section>
                            );
                        }

                        if (section.people?.length) {
                            return (
                                <Section key={section.id} id={section.id} title={section.title}>
                                    {section.body ? <p>{section.body}</p> : null}
                                    <div className="grid">
                                        {section.people.map((p, idx) => (
                                            <div key={`${p.name}-${idx}`} className="card">
                                                <div className="cardTitle">{p.name}</div>
                                                <div className="cardText">{p.role}</div>
                                                {p.email ? (
                                                    <a className="cardLink" href={`mailto:${p.email}`}>
                                                        {p.email}
                                                    </a>
                                                ) : (
                                                    <div className="cardHint">Add email in `PythonBackend/content.json`.</div>
                                                )}
                                            </div>
                                        ))}
                                    </div>
                                </Section>
                            );
                        }

                        if (section.timeline?.length) {
                            return (
                                <Section key={section.id} id={section.id} title={section.title}>
                                    {section.body ? <p>{section.body}</p> : null}
                                    <ul className="list">
                                        {section.timeline.map((t, idx) => (
                                            <li key={`${t.milestone}-${idx}`} className="listItem">
                                                <div className="listTitle">{t.milestone}</div>
                                                <div className="listText">{t.date || 'TBD'}</div>
                                            </li>
                                        ))}
                                    </ul>
                                </Section>
                            );
                        }

                        return (
                            <Section key={section.id} id={section.id} title={section.title}>
                                {section.body ? <p>{section.body}</p> : <p className="muted">Add content in `PythonBackend/content.json`.</p>}
                                {section.links?.length ? (
                                    <div className="grid">
                                        {section.links.map((l, idx) => (
                                            <div key={`${l.label}-${idx}`} className="card">
                                                <div className="cardTitle">{l.label}</div>
                                                {l.url ? (
                                                    <a className="cardLink" href={l.url} target="_blank" rel="noreferrer">
                                                        Open
                                                    </a>
                                                ) : (
                                                    <div className="cardHint">Add a URL in `PythonBackend/content.json`.</div>
                                                )}
                                            </div>
                                        ))}
                                    </div>
                                ) : null}
                            </Section>
                        );
                    })}

                <Section id="announcements" title="Announcements">
                    <div className="announceForm">
                        <input
                            className="input"
                            type="text"
                            name="name"
                            placeholder="Title"
                            value={newAnnouncement.name}
                            onChange={handleInputChange}
                        />
                        <input
                            className="input"
                            type="text"
                            name="description"
                            placeholder="Details"
                            value={newAnnouncement.description}
                            onChange={handleInputChange}
                        />
                        <button className="button" onClick={addAnnouncement}>
                            Add
                        </button>
                    </div>

                    {announcements.length ? (
                        <ul className="list">
                            {announcements
                                .slice()
                                .reverse()
                                .map(a => (
                                    <li key={a.id} className="listItem">
                                        <div className="listTitle">{a.name}</div>
                                        <div className="listText">{a.description}</div>
                                    </li>
                                ))}
                        </ul>
                    ) : (
                        <p className="muted">No announcements yet.</p>
                    )}
                </Section>

                <Section id="contacts" title="Contacts">
                    {content?.contacts?.length ? (
                        <div className="grid">
                            {content.contacts.map((c, idx) => (
                                <div key={`${c.email}-${idx}`} className="card">
                                    <div className="cardTitle">{c.name}</div>
                                    <div className="cardText">{c.role}</div>
                                    <a className="cardLink" href={`mailto:${c.email}`}>
                                        {c.email}
                                    </a>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <p className="muted">Add contacts in `PythonBackend/content.json`.</p>
                    )}
                </Section>

                <footer className="footer">
                    <div className="muted">© {new Date().getFullYear()} UG Academic Council</div>
                </footer>
            </main>
        </div>
    );
};

export default App;
